#ifndef LOGEN_ENGINE_H
#define LOGEN_ENGINE_H

#include "core/CoreAPI.h"

struct GLFWwindow;

class LOGEN_API Engine {
public:
    static LOGEN_API bool initialize(int width, int height, const char* title);
    static LOGEN_API void renderFrame();
    static LOGEN_API void shutdown();

    static LOGEN_API bool shouldClose();
    static LOGEN_API void pollEvents();

    static LOGEN_API void setClearColor(float red, float green, float blue, float alpha = 1.0f);
    static LOGEN_API GLFWwindow* getWindow();

    // Optional wrappers if you prefer mixed naming styles in runtime code.
    static bool Initialize(int width, int height, const char* title) { return initialize(width, height, title); }
    static void RenderFrame() { renderFrame(); }
    static void Shutdown() { shutdown(); }
    static bool ShouldClose() { return shouldClose(); }
    static void PollEvents() { pollEvents(); }

private:
    Engine() = delete;

    struct State;
    static State& state();
};

#endif // LOGEN_ENGINE_H

